﻿using UnityEngine;
using System.Collections;

public class OnClickCheck : MonoBehaviour {

    PublicVariables PublicVariablesScript;
    /*
        Adds scripts and gets required scripts to operate correcty
    */
    void Start () {
        PublicVariablesScript = GameObject.Find("Player").GetComponent<PublicVariables>();
    }

    /*
        The check that checks if the object is visable and gets the script that will update stats and money
    */
    void Update () {
        int i = -1;
        if (PublicVariablesScript.activeEnemy != null)
        {
            i = PublicVariablesScript.CurrentEnemyIndex;
            if (PublicVariablesScript.enemies[i] != null)
            {
                if (PublicVariablesScript.enemies[i].activeSelf == true)
                {
                    if (Input.GetMouseButtonDown(0))
                    {
                        Vector3 MousePos = Camera.main.ScreenToWorldPoint(Input.mousePosition);

                        Ray MouseRay = new Ray(MousePos, Vector3.forward * -1);

                        RaycastHit hit;

                        if (Physics.Raycast(MouseRay, out hit))
                        {

                            if (hit.collider.GetComponent<Enemy>() != null)
                            {
                                hit.collider.GetComponent<Enemy>().TakeDamage(100);
                            }
                        }
                    }
